/**
 * POST /api/flink/deploy
 *
 * Deploys all HomeBase Flink SQL pipelines to the Confluent Flink compute pool.
 * Should be called once during initial setup (or to redeploy after changes).
 *
 * Protected by CRON_SECRET (same secret used by Vercel cron).
 *
 * Idempotent: skips statements that are already RUNNING.
 */

import { NextRequest, NextResponse } from 'next/server';
import { submitStatement, listStatements, deleteStatement } from '@/lib/flink-rest';

export const runtime = 'nodejs';
export const dynamic = 'force-dynamic';

// The four HomeBase Flink SQL pipelines.
// Statement names must be unique per environment (alphanumeric + hyphens).
const PIPELINES = [
  {
    name: 'homebase-rolling-avg',
    sql: `CREATE TABLE IF NOT EXISTS mortgage_rate_averages (
  rolling_avg_52w DOUBLE,
  current_rate DOUBLE,
  deviation_from_avg DOUBLE
) WITH (
  'connector' = 'kafka',
  'topic' = 'mortgage-rate-averages',
  'properties.bootstrap.servers' = '${process.env.CONFLUENT_BOOTSTRAP_SERVERS ?? ''}',
  'properties.security.protocol' = 'SASL_SSL',
  'properties.sasl.mechanism' = 'PLAIN',
  'properties.sasl.jaas.config' = 'org.apache.kafka.common.security.plain.PlainLoginModule required username="${process.env.CONFLUENT_API_KEY ?? ''}" password="${process.env.CONFLUENT_API_SECRET ?? ''}";',
  'format' = 'json'
);

INSERT INTO mortgage_rate_averages
SELECT
  AVG(rate_30yr_fixed) OVER (
    ORDER BY PROCTIME()
    RANGE BETWEEN INTERVAL '52' WEEK PRECEDING AND CURRENT ROW
  ) AS rolling_avg_52w,
  rate_30yr_fixed AS current_rate,
  rate_30yr_fixed - AVG(rate_30yr_fixed) OVER (
    ORDER BY PROCTIME()
    RANGE BETWEEN INTERVAL '52' WEEK PRECEDING AND CURRENT ROW
  ) AS deviation_from_avg
FROM mortgage_rates;`,
  },
  {
    name: 'homebase-rate-anomalies',
    sql: `CREATE TABLE IF NOT EXISTS rate_anomalies_out (
  anomaly_type STRING,
  current_rate DOUBLE,
  rolling_avg DOUBLE,
  source STRING,
  ts TIMESTAMP(3)
) WITH (
  'connector' = 'kafka',
  'topic' = 'rate-anomalies',
  'properties.bootstrap.servers' = '${process.env.CONFLUENT_BOOTSTRAP_SERVERS ?? ''}',
  'properties.security.protocol' = 'SASL_SSL',
  'properties.sasl.mechanism' = 'PLAIN',
  'properties.sasl.jaas.config' = 'org.apache.kafka.common.security.plain.PlainLoginModule required username="${process.env.CONFLUENT_API_KEY ?? ''}" password="${process.env.CONFLUENT_API_SECRET ?? ''}";',
  'format' = 'json'
);

INSERT INTO rate_anomalies_out
SELECT
  CASE
    WHEN current_rate < rolling_avg_52w - 0.5 THEN 'HISTORICALLY_LOW'
    WHEN current_rate > rolling_avg_52w + 0.5 THEN 'HISTORICALLY_HIGH'
    ELSE 'NORMAL'
  END AS anomaly_type,
  current_rate,
  rolling_avg_52w AS rolling_avg,
  'flink-pipeline' AS source,
  CURRENT_TIMESTAMP AS ts
FROM mortgage_rate_averages
WHERE ABS(current_rate - rolling_avg_52w) > 0.5;`,
  },
  {
    name: 'homebase-psf-anomalies',
    sql: `CREATE TABLE IF NOT EXISTS price_anomalies_out (
  anomaly_type STRING,
  metric STRING,
  value DOUBLE,
  source STRING,
  ts TIMESTAMP(3)
) WITH (
  'connector' = 'kafka',
  'topic' = 'price-anomalies',
  'properties.bootstrap.servers' = '${process.env.CONFLUENT_BOOTSTRAP_SERVERS ?? ''}',
  'properties.security.protocol' = 'SASL_SSL',
  'properties.sasl.mechanism' = 'PLAIN',
  'properties.sasl.jaas.config' = 'org.apache.kafka.common.security.plain.PlainLoginModule required username="${process.env.CONFLUENT_API_KEY ?? ''}" password="${process.env.CONFLUENT_API_SECRET ?? ''}";',
  'format' = 'json'
);

INSERT INTO price_anomalies_out
SELECT
  'PSF_OUTLIER' AS anomaly_type,
  'price_per_sqft' AS metric,
  price / sqft AS value,
  'flink-pipeline' AS source,
  CURRENT_TIMESTAMP AS ts
FROM market_data_seattle
WHERE sqft > 0
  AND (price / sqft) < (
    AVG(price / sqft) OVER (PARTITION BY zip_code ORDER BY PROCTIME()
    RANGE BETWEEN INTERVAL '30' DAY PRECEDING AND CURRENT ROW)
  ) * 0.85;`,
  },
  {
    name: 'homebase-dom-anomalies',
    sql: `CREATE TABLE IF NOT EXISTS dom_anomalies_out (
  anomaly_type STRING,
  metric STRING,
  value DOUBLE,
  source STRING,
  ts TIMESTAMP(3)
) WITH (
  'connector' = 'kafka',
  'topic' = 'dom-anomalies',
  'properties.bootstrap.servers' = '${process.env.CONFLUENT_BOOTSTRAP_SERVERS ?? ''}',
  'properties.security.protocol' = 'SASL_SSL',
  'properties.sasl.mechanism' = 'PLAIN',
  'properties.sasl.jaas.config' = 'org.apache.kafka.common.security.plain.PlainLoginModule required username="${process.env.CONFLUENT_API_KEY ?? ''}" password="${process.env.CONFLUENT_API_SECRET ?? ''}";',
  'format' = 'json'
);

INSERT INTO dom_anomalies_out
SELECT
  'DOM_OUTLIER' AS anomaly_type,
  'days_on_market' AS metric,
  CAST(days_on_market AS DOUBLE) AS value,
  'flink-pipeline' AS source,
  CURRENT_TIMESTAMP AS ts
FROM market_data_seattle
WHERE days_on_market > (
  AVG(days_on_market) OVER (
    ORDER BY PROCTIME()
    RANGE BETWEEN INTERVAL '6' MONTH PRECEDING AND CURRENT ROW
  ) * 1.5
);`,
  },
];

export async function POST(request: NextRequest) {
  // Auth check
  const cronSecret = process.env.CRON_SECRET;
  if (cronSecret) {
    const auth = request.headers.get('authorization');
    if (auth !== `Bearer ${cronSecret}`) {
      return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });
    }
  }

  // Check required env vars
  const missing = [
    'CONFLUENT_ENV_ID',
    'CONFLUENT_FLINK_POOL_ID',
    'CONFLUENT_ORG_ID',
    'CONFLUENT_FLINK_API_KEY',
    'CONFLUENT_FLINK_API_SECRET',
  ].filter((k) => !process.env[k]);

  if (missing.length > 0) {
    return NextResponse.json(
      { error: `Missing env vars: ${missing.join(', ')}` },
      { status: 500 }
    );
  }

  const body = await request.json().catch(() => ({})) as { redeploy?: boolean };
  const redeploy = body?.redeploy === true;

  // Fetch existing statements
  let existing: Awaited<ReturnType<typeof listStatements>> = [];
  try {
    existing = await listStatements();
  } catch (err) {
    console.error('[flink/deploy] Failed to list statements:', err);
    return NextResponse.json({ error: String(err) }, { status: 502 });
  }

  const existingByName = new Map(existing.map((s) => [s.name, s]));

  const results: Record<string, string> = {};

  for (const pipeline of PIPELINES) {
    const current = existingByName.get(pipeline.name);
    const phase = current?.status?.phase;

    // Already running and no forced redeploy — skip
    if (phase === 'RUNNING' && !redeploy) {
      results[pipeline.name] = 'already-running';
      continue;
    }

    // Delete stale statement before resubmitting
    if (current && redeploy) {
      try {
        await deleteStatement(pipeline.name);
        console.log(`[flink/deploy] Deleted ${pipeline.name} for redeploy`);
      } catch (err) {
        console.warn(`[flink/deploy] Could not delete ${pipeline.name}:`, err);
      }
    }

    try {
      await submitStatement({ name: pipeline.name, sql: pipeline.sql });
      results[pipeline.name] = 'submitted';
      console.log(`[flink/deploy] Submitted ${pipeline.name}`);
    } catch (err) {
      results[pipeline.name] = `error: ${String(err)}`;
      console.error(`[flink/deploy] Failed to submit ${pipeline.name}:`, err);
    }
  }

  return NextResponse.json({ success: true, pipelines: results });
}

/**
 * POST /api/flink/deploy
 *
 * Deploys HomeBase Flink SQL pipelines to the Confluent managed compute pool.
 * Uses the native 'confluent' connector (no manual SASL/SSL config needed).
 *
 * Each pipeline is split into two statements:
 *   1. DDL  — CREATE TABLE IF NOT EXISTS (sink table)
 *   2. DML  — INSERT INTO ... SELECT (continuous query)
 *
 * The source table (mortgage_rates) is assumed to already exist in Confluent.
 *
 * Protected by CRON_SECRET. Idempotent — skips RUNNING statements.
 * Pass { "redeploy": true } in the body to force a full teardown + redeploy.
 */

import { NextRequest, NextResponse } from 'next/server';
import { submitStatement, listStatements, deleteStatement } from '@/lib/flink-rest';

export const runtime = 'nodejs';
export const dynamic = 'force-dynamic';

/**
 * Each pipeline entry has:
 *  - ddlName  : statement name for the CREATE TABLE
 *  - dmlName  : statement name for the INSERT INTO
 *  - ddl      : sink table DDL  (uses 'connector' = 'confluent')
 *  - dml      : continuous INSERT INTO query
 */
const PIPELINES: Array<{ ddlName: string; dmlName: string; ddl: string; dml: string }> = [
  // ── 1. Rate anomaly detection ────────────────────────────────────────────
  {
    ddlName: 'homebase-rate-anomalies-ddl',
    dmlName: 'homebase-rate-anomalies-dml',
    ddl: `CREATE TABLE IF NOT EXISTS rate_anomalies (
  current_rate DOUBLE,
  rolling_avg  DOUBLE,
  deviation    DOUBLE,
  anomaly_type STRING
) WITH (
  'connector'    = 'confluent',
  'kafka.topic'  = 'rate-anomalies',
  'value.format' = 'json-registry'
);`,
    dml: `INSERT INTO rate_anomalies
SELECT
  current_rate,
  rolling_avg,
  current_rate - rolling_avg AS deviation,
  CASE
    WHEN current_rate < rolling_avg - 0.5 THEN 'HISTORICALLY_LOW'
    WHEN current_rate > rolling_avg + 0.5 THEN 'HISTORICALLY_HIGH'
    ELSE 'NORMAL'
  END AS anomaly_type
FROM (
  SELECT
    rate_30yr_fixed AS current_rate,
    AVG(rate_30yr_fixed) OVER (
      ORDER BY ts
      ROWS BETWEEN 52 PRECEDING AND CURRENT ROW
    ) AS rolling_avg
  FROM mortgage_rates
)
WHERE current_rate < rolling_avg - 0.5
   OR current_rate > rolling_avg + 0.5;`,
  },

  // ── 2. Price-per-sqft outlier detection ──────────────────────────────────
  {
    ddlName: 'homebase-price-anomalies-ddl',
    dmlName: 'homebase-price-anomalies-dml',
    ddl: `CREATE TABLE IF NOT EXISTS price_anomalies (
  anomaly_type STRING,
  metric       STRING,
  value        DOUBLE
) WITH (
  'connector'    = 'confluent',
  'kafka.topic'  = 'price-anomalies',
  'value.format' = 'json-registry'
);`,
    dml: `INSERT INTO price_anomalies
SELECT
  'PSF_OUTLIER'    AS anomaly_type,
  'price_per_sqft' AS metric,
  price / sqft     AS value
FROM market_data_seattle
WHERE sqft > 0
  AND price / sqft < AVG(price / sqft) OVER (
    PARTITION BY zip_code
    ORDER BY ts
    ROWS BETWEEN 30 PRECEDING AND CURRENT ROW
  ) * 0.85;`,
  },

  // ── 3. Days-on-market outlier detection ──────────────────────────────────
  {
    ddlName: 'homebase-dom-anomalies-ddl',
    dmlName: 'homebase-dom-anomalies-dml',
    ddl: `CREATE TABLE IF NOT EXISTS dom_anomalies (
  anomaly_type STRING,
  metric       STRING,
  value        DOUBLE
) WITH (
  'connector'    = 'confluent',
  'kafka.topic'  = 'dom-anomalies',
  'value.format' = 'json-registry'
);`,
    dml: `INSERT INTO dom_anomalies
SELECT
  'DOM_OUTLIER'    AS anomaly_type,
  'days_on_market' AS metric,
  CAST(days_on_market AS DOUBLE) AS value
FROM market_data_seattle
WHERE days_on_market > AVG(days_on_market) OVER (
    ORDER BY ts
    ROWS BETWEEN 180 PRECEDING AND CURRENT ROW
  ) * 1.5;`,
  },
];

// All statement names (DDL + DML) so we can check / delete them
const ALL_STATEMENT_NAMES = PIPELINES.flatMap((p) => [p.ddlName, p.dmlName]);

export async function POST(request: NextRequest) {
  // Auth
  const cronSecret = process.env.CRON_SECRET;
  if (cronSecret) {
    const auth = request.headers.get('authorization');
    if (auth !== `Bearer ${cronSecret}`) {
      return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });
    }
  }

  // Env check
  const missing = [
    'CONFLUENT_ENV_ID',
    'CONFLUENT_FLINK_POOL_ID',
    'CONFLUENT_ORG_ID',
    'CONFLUENT_FLINK_API_KEY',
    'CONFLUENT_FLINK_API_SECRET',
  ].filter((k) => !process.env[k]);

  if (missing.length > 0) {
    return NextResponse.json(
      { error: `Missing env vars: ${missing.join(', ')}` },
      { status: 500 }
    );
  }

  const body = (await request.json().catch(() => ({}))) as { redeploy?: boolean };
  const redeploy = body?.redeploy === true;

  // Fetch existing statements
  let existing: Awaited<ReturnType<typeof listStatements>> = [];
  try {
    existing = await listStatements();
  } catch (err) {
    return NextResponse.json({ error: String(err) }, { status: 502 });
  }

  const existingByName = new Map(existing.map((s) => [s.name, s]));
  const results: Record<string, string> = {};

  for (const pipeline of PIPELINES) {
    // ── DDL statement ──────────────────────────────────────────────────────
    const existingDdl = existingByName.get(pipeline.ddlName);
    const ddlPhase = existingDdl?.status?.phase;

    if (ddlPhase === 'COMPLETED' && !redeploy) {
      // DDL (CREATE TABLE IF NOT EXISTS) completes immediately — normal
      results[pipeline.ddlName] = 'already-completed';
    } else {
      if (existingDdl && redeploy) {
        await deleteStatement(pipeline.ddlName).catch(() => {});
      }
      try {
        await submitStatement({ name: pipeline.ddlName, sql: pipeline.ddl });
        results[pipeline.ddlName] = 'submitted';
      } catch (err) {
        results[pipeline.ddlName] = `error: ${String(err)}`;
        console.error(`[flink/deploy] DDL failed for ${pipeline.ddlName}:`, err);
        // Don't submit DML if DDL failed
        results[pipeline.dmlName] = 'skipped (DDL failed)';
        continue;
      }
    }

    // ── DML statement (continuous INSERT INTO) ─────────────────────────────
    const existingDml = existingByName.get(pipeline.dmlName);
    const dmlPhase = existingDml?.status?.phase;

    if (dmlPhase === 'RUNNING' && !redeploy) {
      results[pipeline.dmlName] = 'already-running';
      continue;
    }

    if (existingDml && redeploy) {
      await deleteStatement(pipeline.dmlName).catch(() => {});
    }

    try {
      await submitStatement({ name: pipeline.dmlName, sql: pipeline.dml });
      results[pipeline.dmlName] = 'submitted';
      console.log(`[flink/deploy] Started pipeline: ${pipeline.dmlName}`);
    } catch (err) {
      results[pipeline.dmlName] = `error: ${String(err)}`;
      console.error(`[flink/deploy] DML failed for ${pipeline.dmlName}:`, err);
    }
  }

  const allRunning = ALL_STATEMENT_NAMES
    .filter((n) => n.endsWith('-dml'))
    .every((n) => results[n] === 'submitted' || results[n] === 'already-running');

  return NextResponse.json({ success: true, allRunning, statements: results });
}
